window.bookSummaryJSON = "<p>A collection of timeless Westerns from some of the most well-known authors of the genre, including Zane Grey and Max Brand: \"The Little Gold Miners\" by Joaquin Miller, \"Bulger's Reputation\" by Bret Harte, \"The Leaf of Red Rose\" by W.H.H. Murray, \"The Secret of Macarger's Gulch\" by Ambrose Bierce, \"The Californian's Tale\" by Mark Twain, \"Twelve O'Clock\" by Stephen Crane, \"The Vengeance of Padre Arroyo\" by Gerturde Atherton, \"A Deal in Wheat\" by Frank Norris, \"The Caballero's Way\" by O. Henry, \"On the Divide\" by Willa Cather, \"Timberline\" by Owen Wister, \"The Passing of Black Eagle\" by O. Henry, \"Ananias Green\" by B. M. Bower, \"Lightening\" by Zane Grey, \"Pardon of Becky Day\" by John Fox, and \"The Laughter of Slim Malone\" by Max Brand.</p>"; 
